// Live weather on the LCD. Scripts run on your computer, so http_get uses
// the PC network -- the chip itself needs no Wi-Fi. Press the button (or
// wait for the auto-fetch at start) to pull wttr.in and print it on the
// ST7735; the reply lands in on_http(status, body).
//
// You are `refresh`; `screen` is the LCD, driven by lcd_init.

fn fetch() {
    http_get("https://wttr.in/?format=%t+%C");     // e.g. "+18C Partly cloudy"
}

fn on_start() {
    lcd_init(6, 7, 8, 9, 10);
    lcd_clear(0, 6, 24);
    lcd_rect(0, 0, 128, 15, 20, 60, 120);
    lcd_text(6, 3, "WEATHER", 220, 235, 255);
    lcd_text(8, 40, "fetching...", 150, 180, 220);
    this.n = 0;
    fetch();
}

fn on_press() {
    lcd_rect(8, 36, 116, 50, 0, 6, 24);
    lcd_text(8, 44, "refreshing...", 150, 180, 220);
    fetch();
}

fn on_http(status, body) {
    lcd_rect(8, 36, 116, 50, 0, 6, 24);
    if status == 200 {
        this.n += 1;
        let line = body.trim();
        lcd_text(8, 44, line, 255, 235, 150);
        lcd_text(8, 66, `updated #${this.n}`, 120, 160, 200);
        rgb(0, 30, 8);
        log(`weather: ${line}`);
    } else {
        lcd_text(8, 44, "fetch failed", 255, 120, 120);
        lcd_text(8, 66, `err ${status}`, 200, 120, 120);
        rgb(40, 0, 0);
        log(`http failed: ${status} ${body}`);
    }
}
